#pragma once\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\\n// Correct interface, interface-focused body; avoid extraneous stuff\\\\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\\\\\\\n    const int CHUNKS = 16;\\\\\n    for (size_t i = 0; i < M; ++i) {\\\\\\\\\n        for (size_t j = 0; j < K; j += CHUNKS) {\\\\\\\\\n            float sums[CHUNKS] = {0.0f};\\\\\n            for (size_t k = 0; k < K; ++k) {\\\\\\\\\\n                uint32_t bval = B[k * (K/32) + j/32];\\\\\n                int bt = (bval >> (j&0x1f)) & 1u;\\\\\n                bool sign = bt ? 1.0f : -1.0f;\\\\\n                sums[ k % CHUNKS ] += A[i * K + k] * sign;\\\\\n            }\\\\\\\\\n            // Destination assignment\\\\\n            for (size_t k = 0; k < K; ++k) {\\n                size_t o = j + k;\\n                if (o < K) C[ i*K + o ] = sums[k % CHUNKS];\\n            }\\n        }\\n    }\\n}